---@class LFightIdleAI
local LFightIdleAI = LxClass("LFightIdleAI",nil)
-----------------------------------------------------------------

---行为创建函数
function LFightIdleAI.GenerateAction(action)
	local actionList = LFightIdleAI._actionClsList
	if not actionList then
		local LFightIdleConst = LFightIdleConst
		actionList = {
			[LFightIdleConst.ACTION_SCAN] = "LFightIdleScanAction",
			[LFightIdleConst.ACTION_ATK] = "LFightIdleAtkAction",
			[LFightIdleConst.ACTION_PATROL] = "LFightIdlePatrolAction",
			[LFightIdleConst.ACTION_PATH] = "LFightIdlePathAction",
			[LFightIdleConst.ACTION_BEHIT] = "LFightIdleBeHitAction",
			[LFightIdleConst.ACTION_DOGE] = "LFightIdleDogeAction",
			[LFightIdleConst.ACTION_CHALLENGE] = "LFightIdleChallengeAction",
			[LFightIdleConst.ACTION_SEARCH] = "LFightIdleSearchAction",
			[LFightIdleConst.ACTION_FORWARD] = "LFightIdleForwardAction",
			[LFightIdleConst.ACTION_GOTOBOSS] = "LFightIdleGotoBossAction",
			[LFightIdleConst.ACTION_NONE] = "LFightIdleNoneAction",
		}
		LFightIdleAI._actionClsList = actionList
	end
	local actionClsName = actionList[action]
	if not string.isempty(actionClsName)then
		local actionCls = LxRequire("LApp.gameplay.fightIdle.Action."..actionClsName)
		if actionCls then
			return actionCls:New()
		end
	end
end

------------------------------------------------------------------
function LFightIdleAI:LFightIdleAI()
	--AI主体
	---@type LFightIdleObject
	self._obj = nil

	--行为列表
	---@type table<LFightIdleBaseAction>
	self._actionMap = nil

	--当前行为
	---@type LFightIdleBaseAction
	self._curAction = nil

	self._defaultActionType = 0

	---@type LBaseManager
	self._manager = nil

	self._bStart = false

	self._aiType = 0 -- 0 挂机的 1 剧情的, 10 挂机 新横板跑动
	
	-- 是否可以执行下个UI，用来做弹窗暂停AI
	self._IsCanChangeAction = true
end

-----------------------------------------------------------------
function LFightIdleAI:CreateAI(obj,manager, aiType)
	self._obj = obj

	self._manager = manager
	self._aiType = aiType or 0

	self:InitAction()
end

-----------------------------------------------------------------
function LFightIdleAI:InitAction()
	local obj = self._obj

	local actionList = self:GetObjectActionList()

	local actionMap = {}
	for k,v in ipairs(actionList) do
		local action = LFightIdleAI.GenerateAction(v)
		if action then
			action:Create(obj,self,self._manager)
			actionMap[v] = action
		end
	end

	self._actionMap = actionMap

	self._defaultActionType = self:GetDefaultActionType()
end

function LFightIdleAI:GetDefaultActionType()
	local objType = self._obj:GetObjType()
	if(objType == LFightIdleConst.OBJ_MON) then
		return LFightIdleConst.ACTION_PATROL
	elseif(objType == LFightIdleConst.OBJ_HERO) then
		if self._aiType == 1 then
			return LFightIdleConst.ACTION_SCAN
		elseif self._aiType == 10 then
			return LFightIdleConst.ACTION_NONE
		else
			return LFightIdleConst.ACTION_SEARCH
		end
	elseif(objType == LFightIdleConst.OBJ_MISSION) then
		return LFightIdleConst.ACTION_NONE
	elseif(objType == LFightIdleConst.OBJ_BOSS) then
		return LFightIdleConst.ACTION_NONE
	else
		return LFightIdleConst.ACTION_NONE
	end
end

function LFightIdleAI:GetDefaultAction()
	if not self._defaultActionType then
		self._defaultActionType = self:GetDefaultActionType()
	end
	return self._defaultActionType
end

function LFightIdleAI:GetObjectActionList()
	local objType = self._obj:GetObjType()
	if(objType == LFightIdleConst.OBJ_MON) then
		return {LFightIdleConst.ACTION_NONE,LFightIdleConst.ACTION_PATROL,LFightIdleConst.ACTION_ATK,LFightIdleConst.ACTION_BEHIT}
	elseif(objType == LFightIdleConst.OBJ_HERO) then
		if self._aiType == 1 then
			return {LFightIdleConst.ACTION_NONE,LFightIdleConst.ACTION_SCAN,LFightIdleConst.ACTION_ATK,LFightIdleConst.ACTION_PATH,LFightIdleConst.ACTION_DOGE}
		elseif self._aiType == 10 then
			return {LFightIdleConst.ACTION_NONE, LFightIdleConst.ACTION_FORWARD, LFightIdleConst.ACTION_GOTOBOSS}
		else
			return {LFightIdleConst.ACTION_NONE,LFightIdleConst.ACTION_SEARCH,LFightIdleConst.ACTION_ATK,LFightIdleConst.ACTION_PATH,LFightIdleConst.ACTION_DOGE,LFightIdleConst.ACTION_CHALLENGE}
		end
	elseif(objType == LFightIdleConst.OBJ_MISSION) then
		return {LFightIdleConst.ACTION_NONE,LFightIdleConst.ACTION_BEHIT}
	elseif(objType == LFightIdleConst.OBJ_BOSS) then
		return {LFightIdleConst.ACTION_NONE}
	else
		return {LFightIdleConst.ACTION_NONE}
	end
end

-----------------------------------------------------------------
function LFightIdleAI:StartAI()
	self._bStart = true
	self:ResetAI()
end

function LFightIdleAI:IsStart()
	return self._bStart
end

function LFightIdleAI:StopAI()
	self._bStart = false
	if(self._curAction) then
		self._curAction:StopAction()
		self._curAction = nil
	end
end

function LFightIdleAI:ResetAI()
	if self._curAction then
		self._curAction:StartAction()
		return
	end
	local action = self._actionMap[self._defaultActionType]
	self._curAction = action
	action:StartAction()
end

function LFightIdleAI:IsCurrentAction(actionType)
	if self._curAction and self._curAction:IsAction(actionType) then
		return true
	end
	return false
end

function LFightIdleAI:GetCurAction()
	return self._curAction
end


function LFightIdleAI:SetCanChangeAction(bCanChangeAction)
	self._IsCanChangeAction = bCanChangeAction
end

function LFightIdleAI:IsCanChangeAction()
	return self._IsCanChangeAction 
end

function LFightIdleAI:IsHaveAction(actionType)
	return self._actionMap[actionType] ~= nil
end

function LFightIdleAI:GetAction(actionType)
	return self._actionMap[actionType]
end

function LFightIdleAI:ChangeAction(actionType)
	local newAction = self._actionMap[actionType]
	if(not newAction) then
		return
	end

	local oldAction = self._curAction
	if oldAction == newAction then return end

	if oldAction then oldAction:StopAction() end

	self._curAction = newAction
	newAction:StartAction()
end

function LFightIdleAI:OnRun(time)
	if(not self._bStart) then return end

	if not self._obj:IsReady() then return end

	local curAction = self._curAction
	if(curAction) then
		curAction:OnRun(time)
	end
end

function LFightIdleAI:CircleArea()
	if self._curAction then
		self._curAction:CircleArea()
	end
end

function LFightIdleAI:Destroy()
	self._obj = nil
	if(self._curAction) then
		self._curAction:StopAction()
		self._curAction = nil
	end
	table.removeall(self)
end

return LFightIdleAI